	.SBTTL	INTROMENUPOBMENUX=	130		; bullePOBMENUY=	58LGBMENUX=	497LGBMENUY=	162;--------\\; MENU    >;========/MENU:	LOAD.L	A3,#R16"TXIMAS4	CALL	AFIMAGE	JUMP,NE 90$	CALL	CLRFIFO		; vide le FIFO du clavier10$:	LIB	?GETCAR		; attend souris ...	COMP.W	D3,#KEYMGR	JUMP,EQ 10$	COMP.W	D3,#KEYMMR	JUMP,EQ 10$	COMP.W	D3,#KEYMDR	JUMP,EQ 10$	LOAD.L	A3,#R16"ERMENU1	COMP.W	D3,#KEYMGP	JUMP',EQ 16$	COMP.W	D3,#KEYMMP	JUMP',EQ 16$	COMP.W	D3,#KEYMDP	JUMP',EQ 20$;;?	LOAD.B	D3,#BIPERR;;?	.W	LIB,?BEEP	JUMP	10$16$:	LOAD.B	D3,#BIPERR	LIB	?BEEP	CALL	ERRMENU	JUMP	10$20$:				; clic =>	LOAD.L	A3,#R16"TXMENU	CLR.W	D3	LIB	?MMENU	JUMP,NE 90$	LOAD.L	A3,#R16"ERMENU2	TEST.W	D3	JUMP,EQ 16$	LOAD.L	A3,#R16"ERMENU3	COMP.W	D3,#5	JUMP,NE 16$	LOAD.B	D3,#BIPDONE	LIB	?BEEP;;?	LOAD.L	A3,#R16"ERMENU4;;?	CALL	ERRMENU;;?	LOAD.W	D4,#50*3;;?	.W	NTREL,?DELMS	LOAD.L	A3,#R16"TXIMAS41	CALL	AFIMAGE	JUMP,NE 90$	LOAD.L	A3,#R16"TXIMAS42	CALL	AFIMAGE	JUMP,NE 90$	LOAD.L	A3,#R16"TXIMAS43	CALL	AFIMAGE	JUMP,NE 90$	LOAD.L	A3,#R16"TXIMAS44	CALL	AFIMAGE	JUMP,NE 90$	LOAD.W	D4,#50*2	NTREL	?DELMS90$:	RET;-----------\\; ERRMENU    >;-----------/; Affiche un message dans la bulle.; in	A3.L	^message; out	-; mod	D7.WERRMENU:	PUSHM.L	D2..D4,A3	LOAD.L	D3,#-1	LOAD.L	D4,D3	LIB	?DRMDEF	LOAD.W	D3,#POBMENUY	SWAP.W	D3	LOAD.W	D3,#POBMENUX	LOAD.W	D4,#LGBMENUY	SWAP.W	D4	LOAD.W	D4,#LGBMENUX	LOAD.W	D2,#SETDOT	LIB	?DRMATRIX	; efface la bulle	LIB	?AFTIM	.B	USEGC,GCTBF,GCTBS,GCTBT	.B	MODCAR	.B	PENDOT!CLRDOT	.B	0	.EVEN	ADD.W	D3,#50	SWAP.W	D3	ADD.W	D3,#24	SWAP.W	D340$:	LIB	?SETCURS	SWAP.W	D3	ADD.W	D3,(A0)+ODFCY	SWAP.W	D3	LIB	?AFTEXT	TEST.B	(A3)	JUMP,NE 40$	LIB	?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT	.B	MODCAR	.B	SETDOT	.B	0	.EVEN	POPM.L	D2..D4,A3	RETERMENU1:	.ASCIZ	" "	.ASCIZ	" "	.ASCIZ	"  Il faut utiliser le bouton de"	.ASCIZ	"  droite de la souris !"	.B	0ERMENU2:	.ASCIZ	" "	.ASCIZ	"Il faut maintenir press le bouton"	.ASCIZ	"de droite tout en dplaant la souris"	.ASCIZ	/dans la case intitule "zoom" !/	.ASCIZ	" "	.ASCIZ	"Essayez encore une fois ..."	.B	0ERMENU3:	.ASCIZ	" "	.ASCIZ	"Vous n'avez pas relch le bouton"	.ASCIZ	"de la souris dans la case intitule"	.ASCIZ	/"zoom" !/	.ASCIZ	" "	.ASCIZ	"Recommencez ..."	.B	0ERMENU4:	.ASCIZ	" "	.ASCIZ	" "	.ASCIZ	" "	.ASCIZ	"           Trs bien !"	.B	0	.EVENTXMENU:	.ASCIZ	" "	.B	-1	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICODETRUIT	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" dtruit "	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICODEPLACE	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" dplace "	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICODUPLIQUE	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" duplique "	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICOBLOCNOTES	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" bloc-notes "	.B	-1	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICOZOOM	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" zoom "	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICOTOURNE	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" tourne "	.B	SPACE,USEGC,GCICF,GCICS,GCICT	.B	ICOMIROIR	.B	USEGC,GCTXF,GCTXS,GCTXT,SPACE	.ASCIZ	" miroir "	.B	0	.EVEN	.END